export function initDropZone(dropZoneElement, dotNetRef) {
    function preventDefaults(e) {
        e.preventDefault();
        e.stopPropagation();
    }

    function onDragEnter(e) {
        preventDefaults(e);
        dropZoneElement.classList.add("drag-over");
    }

    function onDragOver(e) {
        preventDefaults(e);
        dropZoneElement.classList.add("drag-over");
    }

    function onDragLeave(e) {
        preventDefaults(e);
        if (!dropZoneElement.contains(e.relatedTarget)) {
            dropZoneElement.classList.remove("drag-over");
        }
    }

    function onDrop(e) {
        preventDefaults(e);
        dropZoneElement.classList.remove("drag-over");

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || "unknown"
        }));

        if (files.length > 0) {
            dotNetRef.invokeMethodAsync("OnFilesDropped", files);
        }
    }

    dropZoneElement.addEventListener("dragenter", onDragEnter);
    dropZoneElement.addEventListener("dragover", onDragOver);
    dropZoneElement.addEventListener("dragleave", onDragLeave);
    dropZoneElement.addEventListener("drop", onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener("dragenter", onDragEnter);
            dropZoneElement.removeEventListener("dragover", onDragOver);
            dropZoneElement.removeEventListener("dragleave", onDragLeave);
            dropZoneElement.removeEventListener("drop", onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone">
    <p class="drop-zone-prompt">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var (file, index) in _files.Select((f, i) => (f, i)))
        {
            <li class="file-entry">
                @if (file.Size > MaxFileSize)
                {
                    <span class="file-error">
                        <strong>@file.Name</strong> &mdash; @FormatSize(file.Size) (@file.Type)
                        — Error: file exceeds 10 MB limit
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@file.Name</strong> &mdash; @FormatSize(file.Size) (@file.Type)
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(index)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private readonly List<FileInfo> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/fileDropZone.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> files)
    {
        _files.AddRange(files);
        StateHasChanged();
        await NotifyParent();
    }

    private async Task RemoveFile(int index)
    {
        _files.RemoveAt(index);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files.Where(f => f.Size <= MaxFileSize).ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        _dotNetRef?.Dispose();
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}

